#include<bits/stdc++.h>
using namespace std;
int n,m,a[21][21],b[21][21],v[21];
long long f1()
{
    long long ans=0;
    for(int i=1;i<=n;i++)
    {
        ans=ans*13+1ll*v[i];
    }
    return ans;
}
void f2(long long x)
{
    for(int i=n;i>=1;i--)
    {
        v[i]=x%13;
        x/=13;
    }
}
unordered_map<long long,int> dp;
int dfs(long long x,bool flag)
{
    if(dp.count(x))
    {
        return dp[x];
    }
    f2(x);
    int ans;
    if(flag)
    {
        ans=-1e9;
    }
    else
    {
        ans=1e9;
    }
    for(int i=1;i<=n;i++)
    {
        if(v[i]<v[i-1])
        {
            v[i]++;
            long long tmp=f1();
            if(flag)
            {
                ans=max(ans,dfs(tmp,0)+a[i][v[i]]);
            }
            else
            {
                ans=min(ans,dfs(tmp,1)-b[i][v[i]]);
            }
            v[i]--;
        }
    }
    dp[x]=ans;
    return ans;
}
int main()
{
    scanf("%d%d",&n,&m);
    for(int i=1;i<=n;i++)
    {
        for(int j=1;j<=m;j++)
        {
            scanf("%d",&a[i][j]);
        }
    }
    for(int i=1;i<=n;i++)
    {
        for(int j=1;j<=m;j++)
        {
            scanf("%d",&b[i][j]);
        }
    }
    for(int i=0;i<=n;i++)
    {
        v[i]=m;
    }
    dp[f1()]=0;
    dfs(0,1);
    printf("%d",dp[0]);
    return 0;
}
